import { cloneElement, type ReactElement } from 'react';

function WithPadding({ u }: { u: ReactElement }) {
  return cloneElement(u, { style: { padding: 8, ...u.props.style } });
}

import { useState } from 'react';

function Panel() {
  const [c, setC] = useState(0);
  return (
    <>
      <Field value={c} onChange={setC} />
      <Readout c={c} />
    </>
  );
}

function withLoading<P extends object>(C: React.ComponentType<P>) {
  return function LoadingWrapper(props: P) {
    return <C {...props} />;
  };
}

function Panel({ children }: { children: React.ReactNode }) {
  return <section className="panel">{children}</section>;
}

class Boundary extends React.Component {
  state = { err: null as Error | null };
  static getDerivedStateFromError(e: Error) {
    return { err: e };
  }
  render() {
    if (this.state.err) return <p>Something broke.</p>;
    return this.props.children;
  }
}

import { lazy, Suspense } from 'react';

const Page = lazy(() => import('./HeavyPage'));

export function App() {
  return (
    <Suspense fallback={<p>Loading…</p>}>
      <Page />
    </Suspense>
  );
}

function Banner({ active }: { active: boolean }) {
  return <div className={active ? 'on' : 'off'}>Hi</div>;
}

import { createPortal } from 'react-dom';

export function Modal({ children }: { children: React.ReactNode }) {
  return createPortal(
    <div role="dialog" className="modal">{children}</div>,
    document.body
  );
}

import { useState } from 'react';

function Counter() {
  const [n, setN] = useState(0);
  return <button onClick={() => setN(n + 1)}>{n}</button>;
}
